import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

const FAQS = [
  { q: "Is it cheaper to rent or buy?", a: "It depends on home price, rent, mortgage rate, down payment, appreciation, investment returns, taxes, insurance, maintenance, and how long you stay." },
  { q: "How do you calculate the break-even point between renting and buying?", a: "Compare cumulative renting cost against cumulative buying cost year by year. The break-even point is the first year when buying becomes cheaper than renting." },
  { q: "What is the price-to-rent ratio?", a: "Price-to-rent ratio compares home price to annual rent. A high ratio often means renting may be more attractive, while a lower ratio may favor buying." },
  { q: "What hidden costs come with buying a home?", a: "Common hidden costs include closing costs, property tax, homeowners insurance, maintenance, repairs, HOA dues, PMI, and selling costs." },
  { q: "When does buying make more financial sense than renting?", a: "Buying usually makes more sense when you plan to stay long enough for appreciation and equity growth to offset upfront and ongoing ownership costs." },
];

const money = (v: number, d = 0) => formatCurrencyValue(Number.isFinite(v) ? v : 0, { maximumFractionDigits: d });
const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";
const pmt = (p: number, rate: number) => { const r = rate / 100 / 12; return r === 0 ? p / 360 : p * r / (1 - Math.pow(1 + r, -360)); };

function row(home: number, downPct: number, rate: number, rent: number, appreciation: number, investReturn: number, year: number) {
  const down = home * downPct / 100;
  const loan = home - down;
  const monthly = pmt(loan, rate);
  const buyCashCost = down + monthly * year * 12 + home * 0.018 * year + home * 0.01 * year + home * 0.03;
  const futureHomeValue = home * Math.pow(1 + appreciation / 100, year);
  const loanBalance = Math.max(0, loan * Math.pow(1 + rate / 100 / 12, year * 12) - monthly * ((Math.pow(1 + rate / 100 / 12, year * 12) - 1) / (rate / 100 / 12 || 1)));
  const equity = Math.max(0, futureHomeValue - loanBalance - futureHomeValue * 0.06);
  const buying = Math.max(0, buyCashCost - equity);
  const renting = rent * 12 * ((Math.pow(1.03, year) - 1) / 0.03) + down * Math.pow(1 + investReturn / 100, year) - down;
  const diff = buying - renting;
  return { year, buying, renting, diff, better: diff <= 0 ? "Buy" : "Rent" };
}

export default function RentVsBuyCalculator() {
  useCurrencyVersion();
  const [home, setHome] = useState(350000);
  const [downPct, setDownPct] = useState(10);
  const [rate, setRate] = useState(6.5);
  const [rent, setRent] = useState(2000);
  const [appreciation, setAppreciation] = useState(3);
  const [investReturn, setInvestReturn] = useState(6);
  const [years, setYears] = useState(10);
  const result = useMemo(() => {
    const rows = Array.from({ length: Math.max(1, years) }, (_, i) => row(home, downPct, rate, rent, appreciation, investReturn, i + 1));
    const final = rows[rows.length - 1];
    const breakEven = rows.find((r) => r.better === "Buy")?.year;
    return { rows, final, breakEven };
  }, [home, downPct, rate, rent, appreciation, investReturn, years]);
  const comparison = [1, 2, 3, 5, 7, 10, 15, 20].map((y) => row(350000, 10, 6.5, 2000, 3, 6, y));

  return (
    <>
      <SEOHead title="Free Rent vs Buy Calculator Online - Find Out If Renting or Buying Is Cheaper Instantly | CalcHive" description="Free online rent vs buy calculator. Compare the total cost of renting vs buying a home over any time period and find your break-even point instantly. 100% free, no signup required." canonical="/rent-vs-buy-calculator" keywords="free rent vs buy calculator, renting vs buying calculator free online, should I rent or buy calculator free, rent or buy home calculator free, break even rent vs buy calculator free" category="Financial Calculators" breadcrumbName="Free Rent vs Buy Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10"><div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Rent vs Buy Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Compare renting versus buying over time and estimate when ownership breaks even.</p></div><AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8"><div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8"><div><label className="text-sm font-semibold text-foreground block mb-2">Home price</label><input type="number" value={home} onChange={(e) => setHome(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Down payment (%)</label><input type="number" value={downPct} onChange={(e) => setDownPct(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Mortgage rate (%)</label><input type="number" value={rate} onChange={(e) => setRate(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Monthly rent</label><input type="number" value={rent} onChange={(e) => setRent(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Home appreciation (%)</label><input type="number" value={appreciation} onChange={(e) => setAppreciation(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Investment return (%)</label><input type="number" value={investReturn} onChange={(e) => setInvestReturn(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Years of comparison</label><input type="number" value={years} onChange={(e) => setYears(Number(e.target.value))} className={inputClass} /></div></div><div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Cheaper Option After {years} Years</p><p className="text-5xl sm:text-6xl font-black text-white">{result.final.better}</p></div><div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Buying cost</p><p className="text-lg font-extrabold text-foreground">{money(result.final.buying)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Renting cost</p><p className="text-lg font-extrabold text-foreground">{money(result.final.renting)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Break-even</p><p className="text-lg font-extrabold text-foreground">{result.breakEven ? `Year ${result.breakEven}` : "After period"}</p></div></div></section><ShareButton />
        <section className="mb-8 space-y-6"><h2 className="text-2xl font-bold text-foreground">How to Calculate Whether Renting or Buying Is Cheaper for Free</h2><p className="text-muted-foreground leading-relaxed">This calculator estimates mortgage costs, ownership expenses, home equity, rent growth, and investment opportunity cost across the selected period.</p><h2 className="text-2xl font-bold text-foreground">How to Find the Break-Even Point Between Renting and Buying</h2><div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Rent vs Buy Break-Even - $350,000 Home vs $2,000/month Rent</caption><thead className="bg-muted/60"><tr>{["Year", "Total Cost Buying", "Total Cost Renting", "Cumulative Difference", "Better Option"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{comparison.map((r) => <tr key={r.year}><td className="py-2.5 px-3 font-semibold">{r.year}</td><td className="py-2.5 px-3">{money(r.buying)}</td><td className="py-2.5 px-3">{money(r.renting)}</td><td className="py-2.5 px-3">{money(Math.abs(r.diff))} {r.diff <= 0 ? "buying ahead" : "renting ahead"}</td><td className="py-2.5 px-3">{r.better}</td></tr>)}</tbody></table></div><h2 className="text-2xl font-bold text-foreground">Free Home Rent vs Purchase Comparison Tool for Everyone</h2><p className="text-muted-foreground leading-relaxed">Use this estimate as a planning tool before comparing real mortgage quotes and local ownership costs.</p></section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section><AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/rent-vs-buy-calculator" headingLevel="h3" /></main>
    </>
  );
}


